/*
 * @name AddAssetToGroupByGroupCaption
 * @date 20.08.2020
 * @author Georg Reckendorfer
 * @param locationThingname	name of the location where the asset should be added to the group
 * @param assetThingname 	name of the asset which should be added to the group at the location
 * @param groupId 			id of the assetGroup where the material should be added
 *
 * Adds a asset to a group at a location by the id of the group and the locationThingname.
 */
var loggerBeginning = "[" + me.name + ":AddAssetToGroupByGroupCaption] ";

logger.info(loggerBeginning + "Adds the asset [" + assetThingname + "] to the group [" + groupCaption + "] at the location [" + locationThingname + "]");

var location = Things[locationThingname];
var assetGroups; //Infotable: HPMC.Core.Asset.Group.DS
var assetGroup; //HPMC.Core.Asset.Group.DS
var assets; //Infotable: HPMC.Core.Asset.MetaData.DS

var asset = Things[assetThingname]; //HPMC.Core.Asset.DS

if (groupCaption === null || groupCaption === undefined) {
    groupCaption = "";
}

if (location !== null && location !== undefined) {
    assetGroups = location.assetGroups;

    assetGroup = assetGroups.Find({ groupCaption: groupCaption });

    if (assetGroup !== null && assetGroup !== undefined) {
        assets = assetGroup.assets;

        if (assets === null || assets === undefined) {
            // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Asset.MetaData.DS)
            assets = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
                dataShapeName: "HPMC.Core.Asset.MetaData.DS"
            });
        }

        if (asset !== null && asset !== undefined) {
            try {
                assets.AddRow({
                    caption: asset.caption,
                    assetThingname: assetThingname
                });

                assetGroup.assets = assets;

                assetGroups.Delete({ groupCaption: groupCaption });
                assetGroups.AddRow({
                    groupId: assetGroup.groupId,
                    groupCaption: assetGroup.groupCaption,
                    groupDescription: assetGroup.groupDescription,
                    assets: assets
                });

                location.assetGroups = assetGroups;
            } catch (e) {
                logger.error(loggerBeginning + "Failed to add asset to group: " + e);
            }
        } else {
            logger.error(loggerBeginning + "Can not add asset to group because asset [" + assetThingname + "] does not exist.");
        }
    } else {
        logger.error(loggerBeginning + "Can not add asset to group because groupId [" + groupCaption + "] does not exist.");
    }
} else {
    logger.error(loggerBeginning + "Can not add asset to group, because the location [" + locationThingname + "] does not exist.");
}


/*
    * @name AddAssetToGroupByGroupId
    * @date 20.08.2020
    * @author Georg Reckendorfer
    * @param locationThingname	name of the location where the asset should be added to the group
    * @param assetThingname 	name of the asset which should be added to the group at the location
    * @param groupId 			id of the assetGroup where the material should be added
    * 
    * Adds a asset to a group at a location by the id of the group and the locationThingname.
    */
    var loggerBeginning = "[HPMC.Asset.Helper:AddAssetToGroupByGroupId] ";

    //logger.info(loggerBeginning + "Try to add the asset [" + assetThingname + "] to the group [" + groupId + "] at the location [" + locationThingname + "]");

    var location = Things[locationThingname];
    var assetGroups; //Infotable: HPMC.Core.Asset.Group.DS
    var assetGroup; //HPMC.Core.Asset.Group.DS
    var assets; //Infotable: HPMC.Core.Asset.MetaData.DS

    var asset = Things[assetThingname]; //HPMC.Core.Asset.DS

    if (groupId === null || groupId === undefined) { 
        groupId = "";
    }

    if(location !== null && location !== undefined){

        assetGroups = location.assetGroups;

        assetGroup = assetGroups.Find({groupId : groupId});

        if(assetGroup !== null && assetGroup !== undefined){

            assets = assetGroup.assets;

            if(assets === null || assets === undefined){
                // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Asset.MetaData.DS)
            	assets = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
        						infoTableName : "InfoTable",
        						dataShapeName : "HPMC.Core.Asset.MetaData.DS"
    					});
            }

            if(asset !== null && asset !== undefined){ 
            	try{
                    assets.AddRow({
                        caption: asset.caption,
                        assetThingname: assetThingname
                    });

                    assetGroup.assets = assets;

                    assetGroups.Delete({groupId : groupId});
                    assetGroups.AddRow({
                        groupId: groupId,
                        groupCaption: assetGroup.groupCaption,
                        groupDescription: assetGroup.groupDescription,
                        assets: assets
                    });

                    location.assetGroups = assetGroups;
                }catch(e){
                	logger.error(loggerBeginning + "Failed to add asset to group: " + e);	    
                }

            }else {
            	logger.error(loggerBeginning + "Can not add asset to group because asset [" + assetThingname + "] does not exist.");  
            }

        }else{
        	logger.error(loggerBeginning + "Can not add asset to group because groupId [" + groupId + "] does not exist."); 
        }

    } else{
    	logger.error(loggerBeginning + "Can not add asset to group, because the location [" + locationThingname + "] does not exist."); 
    }


/*
 * @name AddExistingAssetToGroupByGroupId
