var assetGroup; //HPMC.Core.Asset.Group.DS
var assets; //Infotable: HPMC.Core.Asset.MetaData.DS
var locationThingname;
var assetThingname;

//var asset = Things[assetThingname]; //HPMC.Core.Asset.DS

var locationThingTable = ThingTemplates["HPMC.Core.Location.TT"].GetImplementingThingsWithData();

var locationThing;
for (i = 0; i < locationThingTable.getRowCount(); i++) {
    locationThing = Things[locationThingTable[i].name];
    if (locationThing.caption.indexOf(locationCaption) >= 0)
        //==locationCaption)
        locationThingname = locationThing.name;
}
var location = Things[locationThingname];

assetGroups = location.assetGroups;
assetGroup = assetGroups.Find({ groupId: groupId });
assets = assetGroup.assets;
assets.RemoveAllRows();
assetGroups.Delete({ groupId: groupId });
assetGroups.AddRow({
    groupId: groupId,
    groupCaption: machineGroup, //assetGroup.groupCaption,
    groupDescription: assetGroup.groupDescription,
    assets: assets
});

var assetThingTable = ThingTemplates["HPMC.Core.Asset.Saw.TT"].GetImplementingThingsWithData();

var assetThing;
var asset; //HPMC.Core.Asset.DS
for (i = 0; i < assetThingTable.getRowCount(); i++) {
    assetThing = Things[assetThingTable[i].name];

    if (assetThing.locationId.indexOf(locId) >= 0 && assetThing.machineGroup.indexOf(machineGroup) >= 0) {
        //==locationCaption)
        assetThingname = assetThing.name;
        asset = Things[assetThingname]; //HPMC.Core.Asset.DS

        if (location !== null && location !== undefined) {
            assetGroups = location.assetGroups;
            assetGroup = assetGroups.Find({ groupId: groupId });

            if (assetGroup !== null && assetGroup !== undefined) {
                assets = assetGroup.assets;
                if (assets === null || assets === undefined) {
                    // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Asset.MetaData.DS)
                    assets = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "HPMC.Core.Asset.MetaData.DS" });
                }

                if (asset !== null && asset !== undefined) {
                    try {
                        assets.AddRow({
                            caption: asset.caption,
                            assetThingname: assetThingname
                        });

                        assetGroup.assets = assets;

                        assetGroups.Delete({ groupId: groupId });
                        assetGroups.AddRow({
                            groupId: groupId,
                            groupCaption: machineGroup, //assetGroup.groupCaption,
                            groupDescription: assetGroup.groupDescription,
                            assets: assets
                        });

                        location.assetGroups = assetGroups;
                    } catch (e) {
                        logger.error(loggerBeginning + "Failed to add asset to group: " + e);
                    }
                } else {
                    logger.error(loggerBeginning + "Can not add asset to group because asset [" + assetThingname + "] does not exist.");
                }
            } else {
                logger.error(loggerBeginning + "Can not add asset to group because groupId [" + groupId + "] does not exist.");
            }
        } else {
            logger.error(loggerBeginning + "Can not add asset to group, because the location [" + locationThingname + "] does not exist.");
        }
    }
}

