/*
    * @name AddNewAssetFromCSVFile
    * @date 16.02.2021
    * @author Isro Syaeful Iman
    * @return NOTHING
    * @param companyNameBased(BOOLEAN) 			true if location thing search based on companyName
    * [INPROGRESS] add batch of asset from CSV files 
    * [16.02.2021] add asset to location based on company name of location (temporary)
    */
    var result;
    (function(){
        "use strict";
        var loggerBeginning = "["+me.name+":AddNewAssetFromCSVFile] ";
        logger.info(loggerBeginning+" add Assets data to location based on asset groups");
        try{

            let csvData = Resources["CSVParserFunctions"].ReadCSVFile({
                path: "/CSV/machine1.csv" /* STRING */,
                columnMappings: undefined /* STRING */,
                hasHeader: true /* BOOLEAN */,
                longitudeField: undefined /* NUMBER */,
                dateFormat: undefined /* STRING */,
                fileRepository: "HPMC.Core.Repository" /* THINGNAME */,
                latitudeField: undefined /* NUMBER */,
                fieldDelimiter: undefined /* STRING */,
                stringDelimiter: undefined /* STRING */,
                dataShape: "HPMC.Core.CSVMachineList.DS" /* DATASHAPENAME */
            });
            for (let i=0;i<csvData.length;i++){
                let data = csvData.rows[i];
                if (companyNameBased){
                    if (data.companyName!==""){
                        result = me.AddNewAssetToLocationAssetGroup({
                            machineGroup: data.assetGroupCaption /* STRING */,
                            machineGroupDescription:  data.assetGroupDescription /* STRING */,
                            companyName:  data.companyName /* STRING */,
                            machineType:  data.machineType /* THINGTEMPLATENAME */,
                            groupId:  data.assetGroupId /* STRING */
                        });
                    }
            	} else {
                    if (data.locId.length>0 && data.ucId.length>0)
                        result = me.AddNewAssetToLocationAssetGroupByUcIdAndLocId({
                            machineGroup: data.assetGroupCaption /* STRING */,
                            machineGroupDescription: data.assetGroupIdDescription /* STRING */,
                            machineType: data.machineType /* THINGTEMPLATENAME */,
                            groupId: data.assetGroupId /* STRING */,
                            ucId: data.ucId /* STRING */,
                            locId: data.locId /* STRING */
                        });
                }
            }
        }catch(error){

        	logger.error(loggerBeginning+" can't add Assets data to location - ERROR:"+error);
        }

    }());


/*
    * @name AddNewAssetToLocationAssetGroup
    * @date 04.02.2021
    * @author Isro Syaeful Iman
    * @param machineGroup(STRING)				machine group of the machine assets (as groupId as well)
    * @param machineGroupDescription(STRING)	machine group description of the machine assets
    * @param companyName(STRING)				company location name of the location thing 
    * @param machineType(THINGTEMPLATE)			machine type for naming convention of new machine asset
    * @return NOTHING
    */
    var result;
    (function(){
        "use strict";
        var loggerBeginning = "["+me.name+":AddNewAssetToLocationAssetGroup] ";
        try{
        	logger.info(loggerBeginning+" check machine type is exist");
            let machineTypeList =me.GetConfigurationTable({
                tableName: "machineTypeList" /* STRING */
            });
            machineTypeList.Filter({thing_template:machineType});
            let typeCaption = machineTypeList.caption;
            let typeThingTemplate = machineTypeList.thing_template;

            try{
        		logger.info(loggerBeginning+" add new asset to location thing");
                let locations = me.QueryAllLocations();
                companyName = (companyName.replace("(","*")).replace(")","*");
                location = Resources["InfoTableFunctions"].Query({
                    t:locations,
                    query:{
                        "filters":{
                            "type":"LIKE",
                            "fieldName":"companyName",
                            "value":"*"+companyName+"*"
                        }
                    }
                });
                let locationThingName =location[0].name;
                let assetGroups = Things[locationThingName].assetGroups;
                try {
                    logger.info(loggerBeginning+" start to search company location thing");
                    let assetGroup = Resources["InfoTableFunctions"].Query({
                        t:assetGroups,
                        query:{
                            "filters":{
                                "type":"EQ",
                                "fieldName":"groupId",
                                "value":groupId
                            }
                        }
                    });

                    machineGroupDescription = (machineGroupDescription===undefined)?"":machineGroupDescription;
                    if (assetGroup.length===0){ // if asset group not found
                        me.CreateAssetGroup({
                            locationThingname: locationThingName /* THINGNAME */,
                            groupId: groupId /* STRING */,
                            groupCaption: machineGroup /* STRING */,
                            groupDescription:  machineGroupDescription /* STRING */
                        });
                        assetGroups = Things[locationThingName].assetGroups;
                        assetGroup = Resources["InfoTableFunctions"].Query({
                            t:assetGroups,
                            query:{
                                "filters":{
                                    "type":"EQ",
                                    "fieldName":"groupId",
                                    "value":groupId
                                }
                            }
                        });
                    } 

                    let assets = assetGroup.assets;
                    let assetThingName = me.CreateAssetByTemplate({
                        assetTemplateName: typeThingTemplate /* THINGTEMPLATENAME */,
                        assetType: typeCaption /* STRING */
                    });

                    me.AddAssetToGroupByGroupId({
                        locationThingname: locationThingName /* THINGNAME */,
                        assetThingname: assetThingName /* THINGNAME */,
                        groupId: groupId /* STRING */
                    });
                }catch(companyError){
                    logger.error(loggerBeginning+ "cant find company location thing - ERROR:"+companyError);
                }
                result = Things[locationThingName].assetGroups;
            }catch(error){
                logger.error(loggerBeginning+"failed to add asset into location asset groups - ERROR:"+error);
            }
        }catch(machineTypeError){
        	logger.info(loggerBeginning+" machine type doesnt exist");
        }
    }());


/*
    * @name AddNewAssetToLocationAssetGroupByUcIdAndLocId
    * @date 04.02.2021
    * @author Isro Syaeful Iman
    * @param groupId(STRING)					machine group id
    * @param machineGroup(STRING)				machine group of the machine assets
    * @param machineGroupDescription(STRING)	machine group description of the machine assets
    * @param ucId(STRING)						unique company id 
    * @param locId(STRING)						location id 
    * @param machineId(STRING)					machine id 
    * @param machineType(THINGTEMPLATE)			machine type for naming convention of new machine asset
    * @return (STRING) asset thing name
    *
    * create new asset on spesific location based on ucID and locID
    */
    var result;
    (function(){
        "use strict";
        var loggerBeginning = "["+me.name+":AddNewAssetToLocationAssetGroupByUcIdAndLocId] ";
        try{
        	logger.info(loggerBeginning+" start to creating new asset on spesific location based on ucID and locID");
        	logger.info(loggerBeginning+" check machine type is exist");
            machineId = (machineId)||"";
            groupId = (groupId==="" || groupId===null || groupId===undefined) ? "99":groupId;
            if (groupId==="99"){
                logger.warn(loggerBeginning+" group id is empty");
                machineGroup = "Other Machine";
            }

            let machineTypeList =me.GetConfigurationTable({
                tableName: "machineTypeList" /* STRING */
            });
            machineTypeList.Filter({thing_template:machineType});
            let typeCaption = machineTypeList.caption;
            let typeThingTemplate = machineTypeList.thing_template;

            try{
        		logger.info(loggerBeginning+" add new asset to location thing");
                let locations = me.QueryLocationByCompanyID({
                    company_id: ucId /* STRING */
                });
                location = me.QueryLocationByUcIDAndLocId({
                    company_id: ucId /* STRING */,
                    locId: locId /* STRING */
                });
                let locationThingName =location[0].name;
                let assetGroups = Things[locationThingName].assetGroups;
                let assetGroup = Resources["InfoTableFunctions"].Query({
                    t:assetGroups,
                    query:{
                        "filters":{
                            "type":"EQ",
                            "fieldName":"groupId",
                            "value":groupId
                        }
                    }
                });

                machineGroupDescription = (machineGroupDescription===undefined)?"":machineGroupDescription;
                if (assetGroup.length===0){ // if asset group not found
                    me.CreateAssetGroup({
                        locationThingname: locationThingName /* THINGNAME */,
                        groupId: groupId /* STRING */,
                        groupCaption: machineGroup /* STRING */,
                        groupDescription:  machineGroupDescription /* STRING */
                    });
                    assetGroups = Things[locationThingName].assetGroups;
                    assetGroup = Resources["InfoTableFunctions"].Query({
                        t:assetGroups,
                        query:{
                            "filters":{
                                "type":"EQ",
                                "fieldName":"groupId",
                                "value":groupId
                            }
                        }
                    });
                } 
                let assets = assetGroup.assets;
                let assetThingName = me.CreateAssetByTemplate({
                    assetTemplateName: typeThingTemplate /* THINGTEMPLATENAME */,
                    assetType: typeCaption /* STRING */
                });
                Things[assetThingName].assetType = machineTypeList.caption2;
    			Things[assetThingName].locId = locId;
    			Things[assetThingName].ucId = ucId;
    			Things[assetThingName].machineId = machineId;
                me.AddAssetToGroupByGroupId({
                    locationThingname: locationThingName /* THINGNAME */,
                    assetThingname: assetThingName /* THINGNAME */,
                    groupId: groupId /* STRING */
                });
                result = assetThingName;
        		logger.info(loggerBeginning+" success creating new asset on spesific location based on ucID and locID");
            }catch(error){
                logger.error(loggerBeginning+"failed to add asset into location asset groups - ERROR:"+error);
            }
        }catch(machineTypeError){
        	logger.info(loggerBeginning+" machine type doesnt exist");
        }
    }());


/*
 * @name AddNumberOfAssetToLocationAssetGroup
 * @date 04.02.2021
 * @author Isro Syaeful Iman
 * @param machineGroup(STRING)				machine group of the machine assets (as groupId as well)
 * @param machineGroupDescription(STRING)	machine group description of the machine assets
 * @param companyName(STRING)				company location name of the location thing
 * @param machineType(THINGTEMPLATE)			machine type for naming convention of new machine asset
 * @param totalNewAsset(INTEEGR)				number of new asset
 * @return (INFOTABLE) asset groups in the location thing
 */
var result;
(function () {
    "use strict";
    var loggerBeginning = "[" + me.name + ":AddNumberOfAssetToLocationAssetGroup] ";
    try {
        logger.error(loggerBeginning + " start to add number of new asset based on machine group and machine type of an asset");
        for (let i = 0; i < totalNewAsset; i++) {
            result = me.AddNewAssetToLocationAssetGroup({
                companyName: companyName /* STRING */,
                machineGroup: machineGroup /* STRING */,
                machineGroupDescription: "" /* STRING */,
                machineType: machineType /* THINGTEMPLATENAME */
            });
        }
    } catch (err) {
        logger.error(loggerBeginning + " can't add asset into location asset group - ERROR:" + err);
    }
})();


/*
     * @name CreateAsset
     * @date 08.03.2022
     * @author Marc Aurel Büttner
     * @params String for create --> similar Asset Templates
     * @return nothing
     * [EDIT] by Marc Aurel Büttner [23.03.2022] Add set permissions 
     */

const CORE_MANAGER = Things["HPMC.Core.Manager"];

const generateThingname = (type) => {
  let assetThingnamevalue = "HPMC.Dynamic.Asset." + type + "." + generateGUID();
  //check if Thing already exists
  while (Things[assetThingnamevalue]) {
    assetThingnamevalue = "HPMC.Dynamic.Asset." + type + "." + generateGUID();
  }
  return assetThingnamevalue;
};

let newThing = "";
let template = "";

//define asset type to be created
if (machineType == "Sawing") {
  let type = assetType.slice(0,3);
  newThing = generateThingname(type);
  template = "HPMC.Core.Asset.Saw.TT";
}
if (machineType == "Milling") {
  let type = assetType;
  newThing = generateThingname(type);
  template = "HPMC.Core.Asset.Milling.TT";
}
if(machineType == "Wet-Draw") {
	let type = assetType;
  	newThing = generateThingname(type);
  	template = "HPMC.Core.Asset.WetDraw.TT";
}
if(machineType == "Annealing") {
	let type = assetType;
    newThing = generateThingname(type);
    template = "HPMC.Core.Asset.Annealing.TT";
}


try {
  if (newThing != "") {
    let today = new Date();
    let descriptionText =
      "created in Thingworx with template on " +
      today +
      " by " +
      Resources["CurrentSessionInfo"].GetCurrentUser();
    // logger.info(me.name + ".CreateAsset Try to create Thing: " + newThing);
    Resources["EntityServices"].CreateThing({
      thingTemplateName: template,
      description: descriptionText,
      projectName: "HPMC.DynamicData",
      name: newThing,
    });
    logger.info(me.name + ".CreateAsset Created new Thing: " + Things[newThing].name);
    Things[newThing].EnableThing();
    Things[newThing].RestartThing();
    logger.info("New Asset [" + newThing + "] was created, enabled and restarted.");

    Things[newThing].caption = equipmentNumber + " - " + machineName;
    Things[newThing].databaseId = machDbId;
    Things[newThing].machineType = machineType;
    Things[newThing].machineSubType = machineSubType != "" ? machineSubType : ""; //optional
    Things[newThing].manufacturer = manufacturer != "" ? manufacturer : ""; //optional
    if (!manufacturingYear) {
      Things[newThing].manufacturingYear = parseInt(manufacturingYear);
    }
    Things[newThing].sapId = sapId != "" ? sapId : ""; //optional
    Things[newThing].serialNumber = serialNumber != serialNumber ? serialNumber : ""; //optional
    Things[newThing].ucId = ucId;
    Things[newThing].locId = locId;
    Things[newThing].machineId = machDbId;
    Things[newThing].assetType = assetType;
    Things[newThing].equipmentNumber = equipmentNumber;
    Things[newThing].machineGroup = machineGroup;
    Things[newThing].machineName = machineName;
    Things[newThing].isConnected = true;
    if (imagePath) {  
      //Things[newThing].assetImage = Things["SystemRepository"].LoadImage({
      //  path: "/AssetPictureUploads/" + imagePath /* STRING */,
      //});
        let assetImage = Things["HPMC.Core.Repository"].LoadImage({
          path: "/Assets/Images/" + imagePath /* STRING */,
        });  

        let fileEnd = imagePath.split(".")[1];

        try{
            Things["HPMC.Core.Repository"].SaveImage({
                path: "/Assets/Images/"+machineName + "." + fileEnd /* STRING */,
                content: assetImage /* IMAGE */
            });
        }catch(err){ //if image already exists, because machine name is the same
            logger.error("Error while storing image for asset: " + err);
        }

        Things["HPMC.Core.Repository"].DeleteFile({
            path: "/Assets/Images/" + imagePath /* STRING */
        });
    }

    //Add Things to Group
    let locationThing = Things["HPMC.Core.Manager"].QueryLocationByUcIDAndLocId({
      company_id: ucId /* STRING */,
      locId: locId /* STRING */
    });

    // logger.warn(me.name + ".CreateAsset locationThing: " + locationThing.toJSON() + " uc:" + ucId);
    me.AddAssetToGroupByGroupId({
      locationThingname: locationThing.name /* THINGNAME */,
      groupId: machineGroupId /* STRING */,
      assetThingname: newThing /* THINGNAME */,
    });

    //Set Permissions
    let permissionGroup = me.getAvailableVisibiltyGroupForAsset({
      locId: locId /* STRING */,
      ucId: ucId /* STRING */,
    });
    // let visibilityGroup = "HPMC.Voestalpine.Orga:" + permissionGroup.replace("HPMC.", "");

    Things[newThing].AddRunTimePermission({
      principal: permissionGroup /* STRING */,
      allow: true /* BOOLEAN */,
      resource: "*" /* STRING */,
      type: "PropertyRead" /* STRING */,
      principalType: "Group" /* STRING */,
    });
    Things[newThing].AddRunTimePermission({
      principal: permissionGroup /* STRING */,
      allow: true /* BOOLEAN */,
      resource: "*" /* STRING */,
      type: "ServiceInvoke" /* STRING */,
      principalType: "Group" /* STRING */,
    });


  }
} catch (err) {
  logger.error("Error at " + me.name + ".CreateAsset [" + err.lineNumber + "]:" + err.message);
  Resources["EntityServices"].DeleteThing({ name: newThing });

  let assetGroup = locationThing.assetGroups.Find({ groupId: machineGroupId });
  let asset = assetGroup.assets.Find({
    assetThingname: newThing,
  });

  if (asset) {
    me.RemoveAssetFromAssetGroupAtLocation({
      locationThingname: locationThing.name /* THINGNAME */,
      groupId: machineGroupId /* STRING */,
      assetThingname: newThing /* STRING */,
    });
  }
  logger.error(
    "Error at " + me.name + ".CreateAsset [" + err.lineNumber + "]:" + err.message
  );
}


/*
    * @name CreateAssetByTemplate
    * @date 20.08.2020
    * @author Georg Reckendorfer
    * @param assetTemplateName	name of the asset-Template which should be created
    * @return thingname 		name of the thing(asset) which have been created
    *
    * Create a asset at the given location in the given group.
    */
    var loggerBeginning = "[HPMC.Asset.Helper:CreateAsset] ";

    logger.info(loggerBeginning + "Create a asset with the template [" + assetTemplateName + "]");

    var projectName = "HPMC.PJ";

    var dateTime = dateFormat(new Date(), "dd.MM.yyyy HH:mm");
    var descriptionText = "created in ThingWorx on "+ dateTime +" by " +Resources["CurrentSessionInfo"].GetCurrentUser();
    var assetThingname;

    function generateAssetThingname(){
        if(assetTemplateName !== null && assetTemplateName !== undefined && assetType !== null && assetType.length !== 0){
    		assetThingname = "HPMC.Asset." + assetType + "." + generateGUID();
    	} else{
     		assetThingname = "HPMC.Asset." + generateGUID();
    	}
        return assetThingname;
    }

    assetThingname = generateAssetThingname();

    var newCreatedCaption = "New Asset (" + dateTime +")";

    var newAssetThing;
    var result; //THINGNAME - HPMC.Core.Asset.DS

    //check if assetThingname does already exist
    newAssetThing = Things[assetThingname];
    while(newAssetThing !== null){
        assetThingname = generateAssetThingname();
        newAssetThing = Things[assetThingname];
    }

    try{
        var tags1 = {
            tags : "Application:HPMC.Asset"
        };
        Resources["EntityServices"].CreateThing({
            name: assetThingname /* STRING */,
            description: descriptionText /* STRING */,
            thingTemplateName: assetTemplateName /* THINGTEMPLATENAME */,
            tags: [{vocabulary: "Applications",  
                    vocabularyTerm: "HPMC.Asset"} ] /* TAGS */
        });


        newAssetThing = Things[assetThingname];

        newAssetThing.EnableThing();
        newAssetThing.RestartThing();

        newAssetThing.SetProjectName({
            projectName: projectName /* PROJECTNAME */
        });

        newAssetThing.caption = newCreatedCaption;

        result = newAssetThing.name;
    }catch(e){
    	logger.error(loggerBeginning +"Failed to create the asset: " + e);   
    }


/*
     * @name createAssetByTemplate
     * @date 08.03.2022
     * @author Marc Aurel Büttner
     * @params String for create --> similar Asset Templates
     * @return nothing
     * [EDIT] by Marc Aurel Büttner [23.03.2022] Add set permissions 
     */

    let newThing = "";
    let template = "";

    //define asset type to be created
    if (machineType == "Sawing") {
      let type = assetType.slice(0, -3);
      newThing = generateThingname(type);
      template = "HPMC.Core.Asset.Saw.TT";
    }
    if (machineType == "Milling") {
      let type = assetType;
      newThing = generateThingname(type);
      template = "HPMC.Core.Asset.Milling.TT";
    }

    try {
      if (newThing != "") {
        let today = new Date();
        let descriptionText =
          "created in Thingworx with template on " +
          today +
          " by " +
          Resources["CurrentSessionInfo"].GetCurrentUser();
        logger.info(me.name + ".createAssetByTemplate Try to create Thing: " + newThing);
        Resources["EntityServices"].CreateThing({
          thingTemplateName: template,
          description: descriptionText,
          projectName: "HPMC.PJ",
          name: newThing,
        });
        logger.info(me.name + ".createAssetByTemplate Created new Thing: " + Things[newThing]);
        Things[newThing].EnableThing();
        Things[newThing].RestartThing();
        logger.info("New Asset [" + newThing + "] was created, enabled and restarted.");

        Things[newThing].caption = equipmentNumber + " - " + machineName;
        Things[newThing].databaseId = machDbId;
        Things[newThing].machineType = machineType;
        Things[newThing].machineSubType = machineSubType != "" ? machineSubType : ""; //optional
        Things[newThing].manufacturer = manufacturer != "" ? manufacturer : ""; //optional
        if (!manufacturingYear) {
          Things[newThing].manufacturingYear = parseInt(manufacturingYear);
        }
        Things[newThing].sapId = sapId != "" ? sapId : ""; //optional
        Things[newThing].serialNumber = serialNumber != serialNumber ? serialNumber : ""; //optional
        Things[newThing].ucId = ucId;
        Things[newThing].locId = locId;
        Things[newThing].machineId = machDbId;
        Things[newThing].assetType = assetType;
        Things[newThing].equipmentNumber = equipmentNumber;
        Things[newThing].machineGroup = machineGroupId;
        Things[newThing].machineName = machineName;
        if (imagePath) {  
          //Things[newThing].assetImage = Things["SystemRepository"].LoadImage({
          //  path: "/AssetPictureUploads/" + imagePath /* STRING */,
          //});
            let assetImage = Things["HPMC.Core.Repository"].LoadImage({
                path: "/AssetImage/" + imagePath /* STRING */,
            });  

            let fileEnd = imagePath.split(".")[1];

            try{
                Things["HPMC.Core.Repository"].SaveImage({
                    path: "/AssetImage/"+machineName + "." + fileEnd /* STRING */,
                    content: assetImage /* IMAGE */
                });
            }catch(err){ //if image already exists, because machine name is the same
                logger.error("Error while storing image for asset: " + err);
            }

            Things["HPMC.Core.Repository"].DeleteFile({
                path: "/AssetImage/" + imagePath /* STRING */
            });
        }

        //Add Things to Group
        let locationThing = me.QueryLocationByCompanyID({
          company_id: ucId /* STRING */,
        });

        me.AddAssetToGroupByGroupId({
          locationThingname: locationThing.name /* THINGNAME */,
          groupId: machineGroupId /* STRING */,
          assetThingname: newThing /* THINGNAME */,
        });

        //Set Permissions
        let permissionGroup = me.getAvailableVisibiltyGroupForAsset({
          locId: locId /* STRING */,
          ucId: ucId /* STRING */,
        });
        // let visibilityGroup = "HPMC.Voestalpine.Orga:" + permissionGroup.replace("HPMC.", "");

        Things[newThing].AddRunTimePermission({
          principal: permissionGroup /* STRING */,
          allow: true /* BOOLEAN */,
          resource: "*" /* STRING */,
          type: "PropertyRead" /* STRING */,
          principalType: "Group" /* STRING */,
        });
        Things[newThing].AddRunTimePermission({
          principal: permissionGroup /* STRING */,
          allow: true /* BOOLEAN */,
          resource: "*" /* STRING */,
          type: "ServiceInvoke" /* STRING */,
          principalType: "Group" /* STRING */,
        });
        // Things["HPMC.Asset.Saw.61bce69c-88c5-451d-8a9c-ab51c9b5ce9c"].AddVisibilityPermission({
        //   principal: visibilityGroup /* STRING */,
        //   principalType: "Group" /* STRING */,
        // });


      }
    } catch (err) {
      logger.error(me.name + ":" + err.message);
      Resources["EntityServices"].DeleteThing({ name: newThing });

      let assetGroup = locationThing.assetGroups.Find({ groupId: machineGroupId });
      let asset = assetGroup.assets.Find({
        assetThingname: newThing,
      });

      if (asset) {
        me.RemoveAssetFromAssetGroupAtLocation({
          locationThingname: locationThing.name /* THINGNAME */,
          groupId: machineGroupId /* STRING */,
          assetThingname: newThing /* STRING */,
        });
      }
      logger.error(
        "Error at " + me.name + ".createAssetByTemplate [" + err.lineNumber + "]:" + err.message
      );
    }

    function generateThingname(type) {
      let assetThingnamevalue = "HPMC.Asset." + type + "." + generateGUID();
      //check if Thing already exists
      while (Things[assetThingnamevalue]) {
        assetThingnamevalue = "HPMC.Asset." + type + "." + generateGUID();
      }
      return assetThingnamevalue;
    }


/*
 * @name CreateAssetGroup
 * @date 20.08.2020
 * @author Georg Reckendorfer
 * @param locationThingname	name of the location where the assetGroup should be created
 * @param groupId 			id of the assetGroup which should be created
 * @param groupCaption 		caption of the assetGroup which should be created
 * @param groupDescription	description of the assetGroup which should be created
 * @return string Message success or not
 *
 * Create a assetGroup at the given location.
 * [Marc Aurel Büttner] [01/03/2022]
 * code optimization, stop code without try-catch
 */
var loggerBeginning = "[" + me.name + ":CreateAssetGroup] ";

logger.info(loggerBeginning + "Create a assetGroup at the location: " + locationThingname);

let allExistingGroups = Things[locationThingname].assetGroups;

if (allExistingGroups.Find({ groupId: groupId })) {
    result = Resources["RuntimeLocalizationFunctions"].GetEffectiveToken({ token: "HPMC.CreateGroupNoSuccess" });
} else {
    allExistingGroups.AddRow({
        groupId: groupId,
        groupCaption: groupCaption,
        groupDescription: groupDescription
    });

    Things[locationThingname].assetGroups = allExistingGroups;
    result = Resources["RuntimeLocalizationFunctions"].GetEffectiveToken({ token: "HPMC.CreateGroupSuccess" });
}


let locationThingname = me.QueryLocationByUcIDAndLocId({
    	company_id: ucId /* STRING */ ,
    	locId: locId /* STRING */
    }).name;

    let asset = me.QueryAssetByCompanyLocation({
    	ucId: ucId /* STRING */ ,
    	locId: locId /* STRING */
    });
    if (asset.length > 0) {
    	for (let i = 0; i < asset.length; i++) {
    		let assetThingname = asset[i].name;
    		me.DeleteAssetByThingname({
    			assetThingname: assetThingname /* THINGNAME */ ,
    			locationThingname: locationThingname /* THINGNAME */ ,
    			groupId: "1" /* STRING */
    		});
    	}
    }

    //delete location
    result = Resources["EntityServices"].DeleteThing({
            name: locationThingname /* THINGNAME */
    });


let locationThingname = me.QueryLocationByUcIDAndLocId({
    	company_id: ucId /* STRING */ ,
    	locId: locId /* STRING */
    }).name;
    let location = Things[locationThingname];
    let asset = me.QueryAssetByCompanyLocation({
    	ucId: ucId /* STRING */ ,
    	locId: locId /* STRING */
    });
    if (asset.length > 0) {
    	for (let i = 0; i < asset.length; i++) {
    		let assetThingname = asset[i].name;
    		me.DeleteAssetByThingname({
    			assetThingname: assetThingname /* THINGNAME */ ,
    			locationThingname: locationThingname /* THINGNAME */ ,
    			groupId: "1" /* STRING */
    		});
    	}
    }


/*
 * @name DeleteAssetByThingname
 * @date 20.08.2020
 * @author Georg Reckendorfer
 * @param locationThingname 		name of the location where the asset is located
 * @param groupCaption 				group where the asset is located
 * @param assetThingname 		name of the asset which should be deleted
 *
 * Deletes the asset by the given name.
 * [09.03.2021] Isro Syaeful - CADIT : If locationThingname and groupId are set, the asset will also be deleted in the assetGroup.
 * [02.05.2024] [Marc Aurel Büttner] : Change  groupId to groupCaption  
 */
var loggerBeginning = "[" + me.name + ":DeleteAssetByThingname] ";

logger.info(loggerBeginning + "Delete material [" + assetThingname + "].");

var location = Things[locationThingname];
var assetGroups; //Infotable: HPMC.Core.Asset.Group.DS
var assetGroup; //HPMC.Core.Asset.Group.DS
let assets;

//delete asset from assetGroup if location and groupCaption are given
if (location !== null && location !== undefined) {
    var index = 0;
    assetGroups = location.assetGroups;

    //result = "A";
    if (assetGroups !== null && assetGroups !== undefined) {
        for (let j = 0; j < assetGroups.length; j++) {
            assetGroup = location.assetGroups.rows[j];

            if (assetGroup.groupCaption === groupCaption) {
                try {
                    for (let k = 0; k < assetGroup.assets.length; k++) {
                        if (assetGroup.assets.rows[k].assetThingname == assetThingname) assetGroup.assets.RemoveRow(k);
                    }
                    assets = assetGroup.assets.clone();
                } catch (e) {
                    logger.error(loggerBeginning + "Failed to delete the asset at the location: " + e);
                }
                location.assetGroups.rows[j].assets = assetGroup.assets;
                index = j;
            }
        }

        assetGroup = location.assetGroups.rows[index];
        assetGroups = location.assetGroups;

        assetGroups.Delete({ groupCaption: groupCaption });
        assetGroups.AddRow({
          groupId: assetGroup.groupId,
          groupCaption: assetGroup.groupCaption,
          groupDescription: assetGroup.groupDescription,
          assets: assets,
        });
        result = Things[locationThingname].assetGroups; // assetGroup.assets;
    } else {
        let log = loggerBeginning + "Can not delete asset [" + assetThingname + "] from group [" + groupId + "], because group does not exist.";
        logger.warn(log);
        //result = log;
    }
} else {
    let log = loggerBeginning + "Can not delete asset [" + assetThingname + "] from location [" + locationThingname + "], because location does not exist.";
    logger.warn(log);
    //result = log;
}

// no return
try {
    logger.info("Delete: " + assetThingname);
    Resources["EntityServices"].DeleteThing({
        name: assetThingname /* THINGNAME */
    });
} catch (e) {
    logger.error(loggerBeginning + "Can not delete asset [" + materialThingname + "]: " + e);
}


/*
    * @name DeleteAssetByThingnameAndLocationCaption
    * @date 28.02.2022
    * @author Marc Aurel Büttner
    * @param selectedAsset IT with additional Asset Information eg. HPMC.Core.Asset.DS
    * @return nothing
    */
    try {
        // result: THINGNAME
        let locationThing = me.QueryLocationByCity({
            caption: selectedAsset.locationCaption /* STRING */
        });

        // result: INFOTABLE dataShape: "HPMC.Core.Asset.Group.DS"
        let assetGroups = me.QueryAssetGroups({
            locationThingname: locationThing /* THINGNAME */
        });

        let groupId;
        assetGroups.rows.toArray().forEach(row => {
            row.assets.rows.toArray().forEach(group => {
                if (group.assetThingname == selectedAsset.assetThingname) {
                    groupId = row.groupId;
                }
            });

        });

        // result: INFOTABLE dataShape: ""
        let deleteInfo = me.DeleteAssetByThingname({
            locationThingname: locationThing /* THINGNAME */,
            groupId: groupId /* STRING */,
            assetThingname: selectedAsset.assetThingname /* THINGNAME */
        });

        logger.info("Deleted Asset: " + selectedAsset.caption + ". Thingname: [" + selectedAsset.assetThingname + "]");
    } catch(err) {
        logger.error("Error at " + me.name + ".SERVICE DeleteAssetByThingnameAndLocationCaption [" + err.lineNumber + "]:" + err.message);
    }


/*
    * @name DeleteAssetByUcIdLocIdAndMachineId
    * @date 09.03.2020
    * @author Isro Syaeful Iman (CAD-IT)
    * @param ucId (STRING) 			unique company Id
    * @param locId (STRING) 		location Id
    * @param machine (STRING) 		machine Id
    * @param groupId(STRING)		group id where the asset is located
    * result (INFOTABLE) 			location assetGroups (check purpose only)
    * 
    * Deletes one asset in spesific location Asset Group based on locId, ucId, machineId and group Id 
    */
    var result;
    var loggerBeginning = "["+me.name+":DeleteAssetByUcIdLocIdAndMachineId] ";
    try{
        logger.info(loggerBeginning + "Deletes one asset in spesific location Asset Group.");
        let locationThingname = me.QueryLocationByUcIDAndLocId({
            company_id: ucId /* STRING */,
            locId: locId /* STRING */
        }).name;
        let location = Things[locationThingname];
        let asset = me.QueryAssetByCompanyLocation({
            ucId: ucId /* STRING */,
            locId: locId /* STRING */
        });
        asset.Filter({machineId:machineId});
        if (asset.length>0){
            let assetThingname = asset.name;
            me.DeleteAssetByThingname({
                assetThingname: assetThingname /* THINGNAME */,
                locationThingname: locationThingname /* THINGNAME */,
                groupId: groupId /* STRING */
            });
        }
        result = Things[locationThingname].assetGroups;
    }catch(error){
        logger.error(loggerBeginning + " failed to delete one asset in spesific location Asset Group.");

    }


/*
 * @name DeleteAssetGroupByGroupId
 * @date 20.08.2020
 * @author Georg Reckendorfer
 * @param locationThingname	name of the location where the assetGroup should be deleted
 * @param groupId 			id of the assetGroup which should be deleted
 *
 * Delete assetGroup with given groupId at the given location.
 */
var loggerBeginning = "[" + me.name + ":DeleteAssetGroupByGroupId] ";

logger.info(loggerBeginning + "Delete assetGroup with id = " + groupId + " at location " + locationThingname);

var location = Things[locationThingname];
var tempAssetGroups; //Infotable: HPMC.Core.Asset.Group.DS

if (location !== null && location !== undefined) {
    // get temp assetGroup, delete it and set assetGroup at location
    // otherwise it would not be stored correctly
    tempAssetGroups = location.assetGroups;
    tempAssetGroups.Delete({ groupId: groupId });
    location.assetGroups = tempAssetGroups;
} else {
    logger.error(loggerBeginning + "Can not delete assetGroup, because location " + locationThingname + " is not given or does not exist");
}


/*
 * @name editAsset
 * @date 08.03.2022
 * @author Marc Aurel Büttner
 * @params String for create --> similar Asset Templates
 * @return nothing
 */

// GroupChange --> change Group on Asset!! (Feedback 4 User?)
try {
    logger.info("Edit Properties of Asset [" + oldProperties.assetThingname + "] by " + Resources["CurrentSessionInfo"].GetCurrentUser());

    const editAsset = oldProperties.assetThingname;

    if (oldProperties.manufacturingYear != manufacturingYear) {
        Things[editAsset].manufacturingYear = parseInt(manufacturingYear);
    }
    if (oldProperties.manufacturer != manufacturer) {
        Things[editAsset].manufacturer = manufacturer;
    }
    if (oldProperties.serialNumber != serialNumber) {
        Things[editAsset].serialNumber = serialNumber;
    }
    if (oldProperties.machineId != machineId) {
        Things[editAsset].machineId = machineId;
        Things[editAsset].databaseId = machineId;
    }
    if (oldProperties.machineSubType != machineSubType) {
        Things[editAsset].machineSubType = machineSubType;
    }
    if (oldProperties.sapId != sapId) {
        Things[editAsset].sapId = sapId;
    }

    if (oldProperties.isConnected != isConnected) {
        Things[editAsset].isConnected = isConnected;
    }

    if (oldProperties.machineName != machineName || oldProperties.equipmentNumber != equipmentNumber) {
        Things[editAsset].equipmentNumber = equipmentNumber;
        Things[editAsset].machineName = machineName;
        Things[editAsset].caption = equipmentNumber + " - " + machineName;
    }

    if (imageName) {
        //Things[editAsset].assetImage = Things["SystemRepository"].LoadImage({
        //path: "/AssetPictureUploads/" + imageName /* STRING */,
        //});

        let assetImage = Things["HPMC.Core.Repository"].LoadImage({
            path: "/AssetImage/" + imageName /* STRING */
        });

        let fileEnd = imageName.split(".")[1];

        try {
            Things["HPMC.Core.Repository"].SaveImage({
                path: "/AssetImage/" + machineName + "." + fileEnd /* STRING */,
                content: assetImage /* IMAGE */
            });
        } catch (err) {
            //if image already exists, because machine name is the same
            logger.error("Error while storing image for asset: " + err);
        }

        Things["HPMC.Core.Repository"].DeleteFile({
            path: "/AssetImage/" + imageName /* STRING */
        });
    }

    if (oldMachineGroupId != selectedGroup.groupId) {
        Things[editAsset].machineGroup = selectedGroup.groupCaption;

        let locationThing = me.QueryLocationByCompanyID({
            company_id: oldProperties.ucId /* STRING */
        });

        me.RemoveAssetFromAssetGroupAtLocation({
            locationThingname: locationThing.name /* THINGNAME */,
            groupId: oldMachineGroupId /* STRING */,
            assetThingname: editAsset /* STRING */
        });

        me.AddAssetToGroupByGroupId({
            locationThingname: locationThing.name /* THINGNAME */,
            groupId: selectedGroup.groupId /* STRING */,
            assetThingname: editAsset /* THINGNAME */
        });
    }
} catch (err) {
    logger.error("Error on" + me.name + ".editAsset [" + err.lineNumber + "]:" + err.message + "by Change asset!");
}


/*
 * @name editAsset
 * @date 08.03.2022
 * @author Marc Aurel Büttner
 * @params String for create --> similar Asset Templates
 * @return nothing
 */

// GroupChange --> change Group on Asset!! (Feedback 4 User?)
try {
    logger.info("Edit Properties of Asset [" + oldProperties.assetThingname + "] by " + Resources["CurrentSessionInfo"].GetCurrentUser());

    const editAsset = oldProperties.assetThingname;

    if (oldProperties.manufacturingYear != manufacturingYear) {
        Things[editAsset].manufacturingYear = parseInt(manufacturingYear);
    }
    if (oldProperties.manufacturer != manufacturer) {
        Things[editAsset].manufacturer = manufacturer;
    }
    if (oldProperties.serialNumber != serialNumber) {
        Things[editAsset].serialNumber = serialNumber;
    }
    if (oldProperties.machineId != machineId) {
        Things[editAsset].machineId = machineId;
        Things[editAsset].databaseId = machineId;
    }
    if (oldProperties.machineSubType != machineSubType) {
        Things[editAsset].machineSubType = machineSubType;
    }
    if (oldProperties.sapId != sapId) {
        Things[editAsset].sapId = sapId;
    }

    if (oldProperties.isConnected != isConnected) {
        Things[editAsset].isConnected = isConnected;
    }

    if (oldProperties.machineName != machineName || oldProperties.equipmentNumber != equipmentNumber) {
        Things[editAsset].equipmentNumber = equipmentNumber;
        Things[editAsset].machineName = machineName;
        Things[editAsset].caption = equipmentNumber + " - " + machineName;
    }

    if (imageName) {
        const assetImage = Things["HPMC.Core.Repository"].LoadImage({
            path: "/Assets/Images/" + imageName /* STRING */
        });

        let fileEnd = imageName.split(".")[1];

        try {
            Things["HPMC.Core.Repository"].SaveImage({
                path: "/Assets/Images/" + machineName + "." + fileEnd /* STRING */,
                content: assetImage /* IMAGE */
            });
        } catch (err) {
            //if image already exists, because machine name is the same
            logger.error("Error while storing image for asset: " + err);
        }

        if (imageName != (machineName + "." + fileEnd)) {
            Things["HPMC.Core.Repository"].DeleteFile({
                path: "/Assets/Images/" + imageName /* STRING */
            });
        }
    }

    if (oldMachineGroupId != selectedGroup.groupId) {
        Things[editAsset].machineGroup = selectedGroup.groupCaption;

        let locationThing = me.QueryLocationByCompanyID({
            company_id: oldProperties.ucId /* STRING */
        });

        me.RemoveAssetFromAssetGroupAtLocation({
            locationThingname: locationThing.name /* THINGNAME */,
            groupId: oldMachineGroupId /* STRING */,
            assetThingname: editAsset /* STRING */
        });

        me.AddAssetToGroupByGroupId({
            locationThingname: locationThing.name /* THINGNAME */,
            groupId: selectedGroup.groupId /* STRING */,
            assetThingname: editAsset /* THINGNAME */
        });
    }
} catch (err) {
    logger.error("Error on" + me.name + ".editAsset [" + err.lineNumber + "]:" + err.message + "by Change asset!");
}


