        machineSubType: Things[assetThingname].machineSubType, // STRING
        manufacturer: Things[assetThingname].manufacturer, // STRING
        manufacturingYear: Things[assetThingname].manufacturingYear, // NUMBER
        sapId: Things[assetThingname].sapId, // STRING
        serialNumber: Things[assetThingname].serialNumber, // STRING
        machineId: Things[assetThingname].machineId, // STRING
        locId: Things[assetThingname].locId, // STRING
        ucId: Things[assetThingname].ucId, // STRING
