/*
    * @name GetMachineAssetsFiltered
    * @date 13.12.2020
    * @author Isro Syaeful Iman
    * @param companyId	(STRING)		company Id of asset
    * @param locationId	(STRING)		location Id of asset
    * @param machineType(STRING)		machine type name of asset
    * @param machineGroup(STRING)		machine group name of asset
    * @param allMachine(BOOLEAN)		all machine or connected machine only 
    * @return infotable 		(HPMC.Core.Asset.Base.DS)
    *
    * [COMPLETED] [13/12/2020] 	Return All Assets and filter bar 
    * 							(Country,Company,Location,MachineType,MachineGroup,EquipmentNum.)
    */

    var result;

    (function(){
        "use strict";
        var i;
        if (companyId===null || companyId===undefined)
            companyId="";
        if (locationId===null || locationId===undefined)
            locationId="";
        if (machineType===null || machineType===undefined)
            machineType="";
        if (machineGroup===null || machineGroup===undefined)
            machineGroup="";
        var loggerBeginning = "["+me.name+"GetMachineAssetsFiltered]";

        try {
            logger.info(loggerBeginning + " Query all machine asset thing where the ThingTemplate HPMC.Asset.Saw.TT is implemented and filtered by location ID, company ID, machineType and machine Group");
            result = DataShapes["HPMC.Core.Asset.Base.DS"].CreateValues();

    		tempData = me.QueryAssetByCompanyLocation2({
                ucId: companyId /* STRING */,
                locId: locationId /* STRING */,
                allMachine: allMachine
            });
            for (i=0; i < tempData.length; i++) {
                let data = tempData.rows[i];
                data.locId = locationId;
                data.ucId = companyId;
                if (  (data.machineType.indexOf(machineType)!==-1) && (data.machineGroup.indexOf(machineGroup)!==-1)){
                    if (allMachine===false) {
                        if (data.isConnected ===true)
                            result.AddRow(data);
                    } else
                    	result.AddRow(data);
                }
            }
            result.Sort({name:"caption",ascending:true});
            // logger.info(loggerBeginning + " Service success");
        }
        catch(error){
            logger.error(loggerBeginning + " cannot get filtered machine assret " +" Exception : "+error);
            result = DataShapes["HPMC.Core.Asset.Base.DS"].CreateValues();
        }
    }());


/*
    * @name GetMachineAssetsFilteredDataPerPage
    * @date 13.12.2020
    * @author Isro Syaeful Iman
    * @param locationId			location Id of asset
    * @param machineType		machine type name of asset
    * @param machineGroup		machine group name of asset
    * @param maxDataPerPage		max data per page
    * @param currentPage 		current page number
    * @return infotable 		(HPMC.Core.Asset.Base.DS)
    *
    * [COMPLETED] [11/12/2020] 	Return Assets based on current page navigation and filter bar 
    * 							(Country,Company,Location,MachineType,MachineGroup,EquipmentNum.)
    */

    //type : infotable (HPMC.Core.Asset.Base.DS)
    var result;
    //type : STRING
    var locationId;
    //type : STRING
    var machineType;
    //type : INTEGER
    var maxDataPerPage;
    //type : INTEGER
    var currentPage;

    (function(){
        "use strict";
        var i;
        if (locationId===null || locationId===undefined)
            locationId="";
        if (machineType===null || machineType===undefined)
            machineType="";
        if (machineGroup===null || machineGroup===undefined)
            machineGroup="";

        logger.info("[" + me.name + ": QueryAllLocations]: Query all locations where the ThingTemplate HPMC.Core.Location.TT is implemented.");
        let locationThingTable = ThingTemplates["HPMC.Core.Asset.Saw.TT"].GetImplementingThingsWithData();

        // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Asset.Base.DS)
        let tempData = DataShapes["HPMC.Core.Asset.Base.DS"].CreateValues();

        var location; //thingname for each asset where the ThingTemplate HPMC.Core.Location.TT is implemented.
        for (i = 0; i < locationThingTable.getRowCount(); i++){
            location = Things[locationThingTable[i].name];

            try{
                // check if the location does exist
                if(location !== null){
                    tempData.AddRow(locationThingTable[i]);
                }
            } catch(e) {
                logger.error("Error: " + e);   
            }
        }
        let removeFieldArr = ["description","tags","thingTemplate","assetImage","diameter",
                             "maxMeterPerMinute","maxPowerConsumption","maxRPM",
                             "machineSubType","sawType","sapId","serialNumber","relatedDowntimeReasons",
                             "plcController","commInterface","commProtocol"];
        for (i=0;i<removeFieldArr.length;i++){
            tempData.RemoveField(removeFieldArr[i]);
        }
        tempData.Sort({name: 'caption'});

        // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Asset.Base.DS)
        result= DataShapes["HPMC.Core.Asset.Base.DS"].CreateValues();

    	let dataIndex=0;

        for (i=0; i < tempData.length; i++) {
            let data = tempData.rows[i];
            if ( (data.locationId.indexOf(locationId) != -1) &&
                 (data.machineType.indexOf(machineType)!=-1) && 
                 (data.machineGroup.indexOf(machineGroup)!=-1)
               ){
                if (dataIndex>=(currentPage-1)*maxDataPerPage && dataIndex<(currentPage)*maxDataPerPage)
                	result.AddRow(data);
                dataIndex++;
            }
        }
    }());


/*
    * @name GetMachineGroupDropdownDataWithLocationAndMachineType
    * @date 14.01.2021
    * @author Isro Syaeful Iman
    * @param companyId		ucId or unique company Id
    * @param locationId 	locId or location Id
    * @param machineType	asset Type
    * @return infotable (HPMC.Core.DropdownData.DS)
    *
    * [COMPLETED]	Return dropdown data for Machine Group Filter from all Asset 
    * 				based on location Id and machine type
    */

    var result;
    var loggerBeginning = "["+me.name+":GetMachineGroupDropdownDataWithLocationAndMachineType]";
    (function(){
        "use  strict";
        logger.info(loggerBeginning + " Query all machine group (distinct) on all asset thing on spesific location");
        try{
            let i,j;
            let locationTable;
            let locationFiltered ;
            let assets;

            try{
                machineType = (machineType||"");
                logger.info(loggerBeginning + "Query all asset thing");
                assets = me.QueryAssetByCompanyLocation({
                    ucId: companyId /* STRING */,
                    locId: locationId /* STRING */,
                    allMachine:false
                });


            } catch(err){
                logger.warn(loggerBeginning + " failed to query all asset thing");
                assets = DataShapes["HPMC.Core.Asset.Base.DS"].CreateValues();
            }
            let assetFilterByType = Resources["InfoTableFunctions"].Query({
                    t: assets /* INFOTABLE */,
                    query: {
                    	"filters":{ "fieldName": "machineType", "type": "EQ", "value":machineType }
                    }
                });

            let dataDistinct = Resources["InfoTableFunctions"].Distinct({
                t: assetFilterByType /* INFOTABLE */,
                columns: "machineGroup"
            });

            result = DataShapes["HPMC.Core.DropdownData.DS"].CreateValues();
            for (i=0;i<dataDistinct.length;i++){
                result.AddRow({dropdown_id: dataDistinct.rows[i].machineGroup, dropdown_value:dataDistinct.rows[i].machineGroup});
            }
            logger.info(loggerBeginning + " success to Query all machine group");
        }catch(error){
        	logger.error(loggerBeginning + " Failed to query all machine group");
        }
    }());


