/*
    * @name QueryAllAssets
    * @date 25.08.2020
    * @author Georg Reckendorfer
    * @return overview of all assets
    */
    var loggerBeginning = "[HPMC.Asset.Helper:QueryAllAssets]: ";

    logger.info(loggerBeginning + "Query all assets from every location.");

    // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Asset.DS)
    var result = DataShapes["HPMC.Core.Asset.DS"].CreateValues();

    var allLocations = ThingTemplates["HPMC.Core.Location.TT"].GetImplementingThingsWithData();
    var location; //HPMC.Core.Location.TT
    var assetGroups; //HPMC.Core.Asset.Group.DS
    var asset; //HPMC.Core.Asset.DS
    var permissions = true;

    if (allLocations !== null) {

      for (var i = 0; i < allLocations.getRowCount(); i++) {

        location = allLocations[i];
        assetGroups = location.assetGroups;

    // 	logger.info(loggerBeginning + "Query assets at location [" + location.caption + "].");

        if (assetGroups !== null && assetGroups !== undefined) {

          for (var j = 0; j < assetGroups.getRowCount(); j++) {
            var group = assetGroups[j];
            var allAssets = group.assets;

    //        logger.info(loggerBeginning + "Query assets for group [" + group.groupCaption + "] at location [" + location.caption + "].");

            if (allAssets !== null && allAssets !== undefined) {

            	for (var k = 0; k < allAssets.getRowCount(); k++) {
                    asset = Things[allAssets[k].assetThingname];

                    if (asset !== null && asset !== undefined) {
                        /*permissions = Things[location.name].CheckPermission({
                            name: '*',
                            type: 'PropertyWrite'
                        });*/

                        if (permissions === true) {
    //                         logger.info(loggerBeginning + "Add asset " + asset.databaseId + " to list.");

                            result.AddRow({                            
                                assetImage: asset.assetImage,
                                caption: asset.caption,
                                databaseId: asset.databaseId,
                                machineType: asset.machineType,
                                machineSubType: asset.machineSubType,
                                manufacturer: asset.manufacturer,
                                manufacturingYear: asset.manufacturingYear,
                                sapId: asset.sapId,
                                serialNumber: asset.serialNumber,
                                assetThingname: asset.name,
                                locationCaption: location.caption,
                                groupCaption: group.groupCaption
                            });
                        }
                    }

                  }
            } else {
              logger.info(loggerBeginning + "There are not assets for the group " + group.groupCaption);
            }
          }
        } else {
          logger.info(loggerBeginning + "There are no assetGroups at the location " + location.caption);
        }
      }
    } else {
      logger.warn(loggerBeginning + "There are no locations.");
    }
    result.Sort({name:"databaseId", ascending:true});


/*
 * @name QueryAllAssetsWithFilter
 * @date 02.03.2022
 * @author Marc Aurel Büttner
 * @param selectedCountry(HPMC.Core.Country.DS) 				selected Country
 * @param selectedCompany(HPMC.Core.Company.DS)				selected Company
 * @param selectedLocation(HPMC.Core.DropdownData.DS) 		selected location id
 * @param selectedMachineType(HPMC.Core.DropdownData.DS)		selected machine type name
 * @param selectedMachineGroup(HPMC.Core.DropdownData.DS)		selected machine group name
 * @param selectedCompanyId(STRING) 						selected unique company id
 * @return saws which are related to the group of the given groupId.
 */

//check if data really exists
let countryValues;
if (selectedCountry) {
    countryValues = selectedCountry ? selectedCountry.country_id : false;
}
let companyValues;
if (selectedCompany) {
    companyValues = selectedCompany ? selectedCompany.company_id : false;
}
let locationValues;
if (selectedLocation) {
    locationValues = selectedLocation ? selectedLocation.dropdown_id : false;
}
let machinetypeValues;
if (selectMachineType) {
    machinetypeValues = selectMachineType ? selectMachineType.dropdown_id : false;
}
let machinegroupValues;
if (selectedMachineGroup) {
    machinegroupValues = selectedMachineGroup ? selectedMachineGroup.dropdown_id : false;
}

try {
    //needed after Country & Company selected
    function locationFunction() {
        try {
            alllocations = me.QueryAllLocations();
        } catch (err) {}
        selectedLoc = alllocations.Find({ locId: selectedLocation.dropdown_id });

        assetgroups = selectedLoc.assetGroups;
        assetgroups.rows.toArray().forEach((assetgroup) => {
            if (assetgroup.assets) {
                singlegroup = assetgroup.assets;
                singlegroup.rows.toArray().forEach((asset) => {
                    companyassets.push({
                        type: "EQ",
                        fieldName: "assetThingname",
                        value: asset.assetThingname
                    });
                });
            }
        });

        filter = companyassets;
        params = buildQueryOr(filter);

        allAssets = Resources["InfoTableFunctions"].Query(params);
        return allAssets;
    }

    function buildQueryOr() {
        params = {
            t: allAssets,
            query: {
                filters: {
                    type: "Or",
                    filters: filter
                }
            }
        };

        return params;
    }

    // Get ALL AssetThings (HPMC.Core.Asset.DS)
    let allAssets = me.QueryAllAssets();

    //declaire diffrerent variables
    let alllocations;
    let locations = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "StringArrayElement" });
    let myquery = {};
    let params = {};

    let assetGroups;
    let singlegroup;
    let companyassets = [];

    //only Country is selected (query all assets not possible yet)
    logger.info(me.name + ".QueryAllAssetsWithFilter countryValues: " + countryValues);
    if (countryValues && !companyValues && !locationValues && !machinetypeValues && !machinegroupValues) {
        //INFOTABLE 1Row country_id, country_name, region
        let country = selectedCountry;

        //country_id, company_id, company_name, sub_region, company_acronym
        let allcompanys = Things["HPMC.Core.Manager"].QueryAllCompaniesByUserLocationPermission();

        let companys = Resources["InfoTableFunctions"].CreateInfoTable();
        companys.AddField({ name: "country_id", baseType: "STRING" });
        companys.AddField({ name: "company_id", baseType: "STRING" });

        try {
            //throws error on missing visibility permissions for single location
            alllocations = me.QueryAllLocations();
        } catch (err) {}

        //get available companys of selected country
        allcompanys.rows.toArray().forEach((company) => {
            if (company.country_id == selectedCountry.country_id) {
                companys.AddRow({
                    country_id: company.country_id,
                    company_id: company.company_id
                });
            }
        });
        let compInfo;
        //get all locations of queried companies of selected country
        companys.rows.toArray().forEach((queriedcomp) => {
            compInfo = alllocations.Find({ ucId: queriedcomp.company_id });
            locations.AddRow({ element: compInfo.caption });
        });

        let locationCaptions = [];
        //prepare query
        locations.rows.toArray().forEach((city) => {
            locationCaptions.push({
                type: "EQ",
                fieldName: "locationCaption",
                value: city.element
            });
        });

        filter = locationCaptions;
        params = buildQueryOr(filter);

        allAssets = Resources["InfoTableFunctions"].Query(params);
    }

    //Company is selected (query all assets not possible yet)
    if (countryValues && companyValues && !locationValues && !machinetypeValues && !machinegroupValues) {
        try {
            alllocations = me.QueryAllLocations();
        } catch (err) {}
        let selectedlocation = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "HPMC.Core.Location.DS" });
        alllocations.rows.toArray().forEach((row) => {
            if (row.ucId == selectedCompany.company_id) {
                selectedlocation.AddRow({
                    address: row.adress,
                    caption: row.caption,
                    location: row.location,
                    locId: row.locId,
                    ucId: row.ucId,
                    assetGroups: row.assetGroups,
                    toolGroups: row.toolGroups,
                    materialGroups: row.materialGroups,
                    name: row.name,
                    companyName: row.companyName
                });
            }
        });

        //prepare query
        selectedlocation.rows.toArray().forEach((location) => {
            assetGroups = location.assetGroups;
            assetGroups.rows.toArray().forEach((assetgroup) => {
                if (assetgroup.assets) {
                    singlegroup = assetgroup.assets;
                    singlegroup.rows.toArray().forEach((asset) => {
                        companyassets.push({
                            type: "EQ",
                            fieldName: "assetThingname",
                            value: asset.assetThingname
                        });
                    });
                }
            });
        });
        filter = companyassets;
        params = buildQueryOr(filter);

        allAssets = Resources["InfoTableFunctions"].Query(params);
    }

    //Location is selected --> based on selected company
    let selectedLoc;
    let selectedAssets;
    if (countryValues && companyValues && locationValues && !machinetypeValues && !machinegroupValues) {
        allLocation = locationFunction(selectedLocation);
    }

    //Asset-Type is selected --> based on selectedLocation
    if (countryValues && selectedCompany && locationValues && machinetypeValues && !machinegroupValues) {
        selectedAssets = locationFunction(selectedLocation);

        myquery = {
            filters: {
                type: "EQ",
                fieldName: "machineType",
                value: selectMachineType.dropdown_id
            }
        };

        params = {
            t: selectedAssets,
            query: myquery
        };

        allAssets = Resources["InfoTableFunctions"].Query(params);
    }
    //MachineGroup selected
    if (countryValues && companyValues && locationValues && machinetypeValues && machinegroupValues) {
        selectedAssets = locationFunction(selectedLocation);

        myquery = {
            filters: {
                type: "EQ",
                fieldName: "groupCaption",
                value: selectedMachineGroup.dropdown_id
            }
        };
        params = {
            t: selectedAssets,
            query: myquery
        };
        allAssets = Resources["InfoTableFunctions"].Query(params);
    }

    result = allAssets;
} catch (err) {
    logger.error("Error at " + me.name + ".QueryAllAssetsWithFilter [" + err.lineNumber + "]:" + err.message);
}


/*
 * @name QueryAllAssetsWithFilter
 * @date 02.03.2022
 * @author Marc Aurel Büttner
 * @param selectedCountry(HPMC.Core.Country.DS) 				selected Country
 * @param selectedCompany(HPMC.Core.Company.DS)				selected Company
 * @param selectedLocation(HPMC.Core.DropdownData.DS) 		selected location id
 * @param selectedMachineType(HPMC.Core.DropdownData.DS)		selected machine type name
 * @param selectedMachineGroup(HPMC.Core.DropdownData.DS)		selected machine group name
 * @param selectedCompanyId(STRING) 						selected unique company id
 * @return saws which are related to the group of the given groupId.
 */

result = (function main() {
    logger.debug("{}.QueryAllAssetsWithFilter start", me.name);
    //check if data really exists
    const isCountrySelected = selectedCountry && selectedCountry.getRowCount() > 0;
    const isCompanySelected = selectedCompany && selectedCompany.getRowCount() > 0;
    const isLocationSelected = selectedLocation && selectedLocation.getRowCount() > 0;
    const isMachineTypeSelected = selectMachineType && selectMachineType.getRowCount() > 0;
    const isMachineGroupSelected = selectedMachineGroup && selectedMachineGroup.getRowCount() > 0;

    // Get ALL AssetThings (HPMC.Core.Asset.DS)
    let allAssets = me.QueryAllAssets();

    try {
        //declaire diffrerent variables
        const allLocations = me.QueryAllLocations();
        //only Country is selected (query all assets not possible yet)
        if (isCountrySelected) {
            allAssets = filterAllAssetsByCountry(allAssets, selectedCountry.country_id, allLocations);
        }

        //Company is selected (query all assets not possible yet)
        if (isCompanySelected) {
            allAssets = filterAllAssetsByCompany(allAssets, selectedCompany.company_id, allLocations);
        }

        if (isLocationSelected) {
            allAssets = filterAllAssetsByLocation(allAssets, selectedLocation.dropdown_id, allLocations);
        }

        if (isMachineTypeSelected) {
            allAssets = filterAllAssetsByMachineType(allAssets, selectMachineType.dropdown_id);
        }

        if (isMachineGroupSelected) {
            allAssets = filterAllAssetsByMachineGroup(allAssets, selectedMachineGroup.dropdown_id);
        }
    } catch (err) {
        logger.error("Error at {}.QueryAllAssetsWithFilter [{}]:{}", me.name, err.lineNumber, err.message);
    }

    logger.debug("{}.QueryAllAssetsWithFilter end", me.name);
    return allAssets;
})();

function filterAllAssetsByCountry(allAssets, countryValue, allLocations) {
    const companys = Resources["InfoTableFunctions"].CreateInfoTable();
    companys.AddField({ name: "country_id", baseType: "STRING" });
    companys.AddField({ name: "company_id", baseType: "STRING" });

    const locations = DataShapes["StringArrayElement"].CreateValues();

    //get available companys of selected country
    //country_id, company_id, company_name, sub_region, company_acronym
    me.QueryAllCompaniesByUserLocationPermission()
        .rows.toArray()
        .forEach((company) => {
            if (company.country_id == countryValue) {
                companys.AddRow({
                    country_id: company.country_id,
                    company_id: company.company_id
                });
            }
        });

    //get all locations of queried companies of selected country
    companys.rows.toArray().forEach((queriedcomp) => {
        locations.AddRow({ element: allLocations.Find({ ucId: queriedcomp.company_id }).caption });
    });

    let locationCaptions = [];
    //prepare query
    locations.rows.toArray().forEach((city) => {
        locationCaptions.push({
            type: "EQ",
            fieldName: "locationCaption",
            value: city.element
        });
    });

    return Resources["InfoTableFunctions"].Query({
        t: allAssets,
        query: {
            filters: {
                type: "Or",
                filters: locationCaptions
            }
        }
    });
}

function filterAllAssetsByCompany(allAssets, companyValue, allLocations) {
    const selectedlocation = DataShapes["HPMC.Core.Location.DS"].CreateValues();

    allLocations.rows.toArray().forEach((row) => {
        if (row.ucId == companyValue) {
            selectedlocation.AddRow({
                address: row.adress,
                caption: row.caption,
                location: row.location,
                locId: row.locId,
                ucId: row.ucId,
                assetGroups: row.assetGroups,
                toolGroups: row.toolGroups,
                materialGroups: row.materialGroups,
                name: row.name,
                companyName: row.companyName
            });
            //selectedlocation.AddRow(row);
        }
    });

    const companyassets = [];
    //prepare query
    selectedlocation.rows.toArray().forEach((location) => {
        location.assetGroups.rows.toArray().forEach((assetgroup) => {
            if (assetgroup.assets) {
                assetgroup.assets.rows.toArray().forEach((asset) => {
                    companyassets.push({
                        type: "EQ",
                        fieldName: "assetThingname",
                        value: asset.assetThingname
                    });
                });
            }
        });
    });

    return Resources["InfoTableFunctions"].Query({
        t: allAssets,
        query: {
            filters: {
                type: "Or",
                filters: companyassets
            }
        }
    });
}

function filterAllAssetsByLocation(allAssets, locationValue, allLocations) {
    const selectedLoc = allLocations.Find({ locId: locationValue });
    const companyassets = [];
    selectedLoc.assetGroups.rows.toArray().forEach((assetgroup) => {
        if (assetgroup.assets) {
            assetgroup.assets.rows.toArray().forEach((asset) => {
                companyassets.push({
                    type: "EQ",
                    fieldName: "assetThingname",
                    value: asset.assetThingname
                });
            });
        }
    });

    return Resources["InfoTableFunctions"].Query({
        t: allAssets,
        query: {
            filters: {
                type: "Or",
                filters: companyassets
            }
        }
    });
}

function filterAllAssetsByMachineType(allAssets, machineTypeValue) {
    return Resources["InfoTableFunctions"].Query({
        t: allAssets,
        query: {
            filters: {
                type: "EQ",
                fieldName: "machineType",
                value: machineTypeValue
            }
        }
    });
}

function filterAllAssetsByMachineGroup(allAssets, machineGroupValue) {
    return Resources["InfoTableFunctions"].Query({
        t: allAssets,
        query: {
            filters: {
                type: "EQ",
                fieldName: "groupCaption",
                value: machineGroupValue
            }
        }
    });
}


