/*
    * @name DeleteAssetByThingname
    * @date 20.08.2020
    * @author Georg Reckendorfer
    * @param locationThingname 		name of the location where the asset is located
    * @param groupId 				group where the asset is located
    * @param assetThingname 		name of the asset which should be deleted
    * 
    * Deletes the asset by the given name.
    * [09.03.2021] Isro Syaeful - CADIT : If locationThingname and groupId are set, the asset will also be deleted in the assetGroup.
    */
    var loggerBeginning = "[HPMC.Asset.Helper:RemoveAssetFromAssetGroupAtLocation] ";

    logger.info(loggerBeginning + "Delete material [" + assetThingname + "].");

    var location = Things[locationThingname];
    var assetGroups; //Infotable: HPMC.Core.Asset.Group.DS
    var assetGroup; //HPMC.Core.Asset.Group.DS
    let assets;

    //delete asset from assetGroup if location and groupId are given
    if(location !== null && location !== undefined){
        var index = 0;
        assetGroups = location.assetGroups;

        //result = "A";
        if(assetGroups !== null && assetGroups !== undefined){
        	//assetGroup = assetGroups.Find({groupId : groupId});
            for (let j=0;j<assetGroups.length;j++){
                assetGroup = location.assetGroups.rows[j];

                if (assetGroup.groupId===groupId){
                    try{
                        for (let k=0;k<assetGroup.assets.length;k++){
                            if (assetGroup.assets.rows[k].assetThingname===assetThingname)
                                assetGroup.assets.RemoveRow(k);
                        }
                        assets = assetGroup.assets.clone();
                    }catch(e){
                        logger.error(loggerBeginning + "Failed to delete the asset at the location: " + e);    
                    }
                    location.assetGroups.rows[j].assets = assetGroup.assets;
                	index = j;
                }
            }

            assetGroup = location.assetGroups.rows[index];
            assetGroups = location.assetGroups;
            assetGroups.Delete({groupId : groupId});
            assetGroups.AddRow({
                groupId: groupId,
                groupCaption: assetGroup.groupCaption,
                groupDescription: assetGroup.groupDescription,
                assets: assets
            });
            result = Things[locationThingname].assetGroups;// assetGroup.assets;
        } else{
            let log = loggerBeginning + "Can not delete asset [" + assetThingname + "] from group [" + groupId + "], because group does not exist.";
        	logger.warn(log);    
            //result = log;
        }
    }else{
        let log = loggerBeginning + "Can not delete asset [" + assetThingname + "] from location [" + locationThingname + "], because location does not exist.";
     	logger.warn(log);
        //result = log;
    }


/*
 * @name SetAssetImageByAssetThingname
