 * @author Georg Reckendorfer
 * @param path				path of the image to load it from the repository and set it
 * @param assetThingname 	asset where the image should be set
 */
var loggerBeginning = "[" + me.name + ":SetAssetImageByAssetThingname] ";

logger.info(loggerBeginning + "Load image from path and set it to asset[" + assetThingname + "]");

var asset = Things[assetThingname];
var assetImage;

if (asset !== null && asset !== undefined) {
    logger.info("Path: " + path);
    try {
        assetImage = Things["HPMC.Core.Repository"].LoadImage({
            path: path /* STRING */
        });
    } catch (e) {
        logger.error(loggerBeginning + "Image can not be loaded from SystemRepository.");
    }

    asset.assetImage = assetImage;

    try {
        Things["HPMC.Core.Repository"].DeleteFile({
            path: path /* STRING */
        });
    } catch (e) {
        logger.warn(loggerBeginning + "Image can not be deleted from SystemRepository.");
    }
} else {
    logger.warn(loggerBeginning + "Can not set image, because asset[" + assetThingname + "] does not exist.");
}


/*
    * @name QueryAllAssets
    * @date 25.08.2020
    * @author Georg Reckendorfer
    * @return overview of all assets
    */
    var loggerBeginning = "[HPMC.Asset.Helper:QueryAllAssets]: ";

    logger.info(loggerBeginning + "Query all assets from every location.");

    // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Asset.DS)
    var result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
      infoTableName: "InfoTable",
      dataShapeName: "HPMC.Core.Asset.DS"
    });

    var allLocations = ThingTemplates["HPMC.Core.Location.TT"].GetImplementingThingsWithData();
    var location; //HPMC.Core.Location.TT
    var assetGroups; //HPMC.Core.Asset.Group.DS
    var asset; //HPMC.Core.Asset.DS
    var permissions = true;

    if (allLocations !== null) {

      for (var i = 0; i < allLocations.getRowCount(); i++) {

        location = allLocations[i];
        assetGroups = location.assetGroups;

     	logger.info(loggerBeginning + "Query assets at location [" + location.caption + "].");

        if (assetGroups !== null && assetGroups !== undefined) {

          for (var j = 0; j < assetGroups.getRowCount(); j++) {
            var group = assetGroups[j];
            var allAssets = group.assets;

            logger.info(loggerBeginning + "Query assets for group [" + group.groupCaption + "] at location [" + location.caption + "].");

            if (allAssets !== null && allAssets !== undefined) {

            	for (var k = 0; k < allAssets.getRowCount(); k++) {
                    asset = Things[allAssets[k].assetThingname];

                    if (asset !== null && asset !== undefined) {

                        if (permissions === true) {
                            logger.info(loggerBeginning + "Add asset type of thing asset " + allAssets[k].assetThingname);
    						let thingTemplate = asset.GetThingTemplate()[0].name;
                            let machineTypeList = me.GetConfigurationTable({
                                tableName: "machineTypeList" /* STRING */
                            });

                            // result: INFOTABLE
                            var machineTypeFiltered = Resources["InfoTableFunctions"].Query({
                                t: machineTypeList /* INFOTABLE */,
                                query: {
                                    "filters":{
                                        "type":"EQ",
                                        "fieldName":"thing_template",
                                        "value":thingTemplate
                                    }
                                } /* QUERY */
                            });
                            if (machineTypeFiltered.length>0){
                                 Things[allAssets[k].assetThingname].assetType = machineTypeFiltered[0].caption2;
                            }else 
                                Things[allAssets[k].assetThingname].assetType ="NOT SET";

                            result.AddRow({                            
                                assetImage: asset.assetImage,
                                caption: asset.caption,
                                databaseId: asset.databaseId,
                                machineType: asset.machineType,
                                machineSubType: asset.machineSubType,
                                manufacturer: asset.manufacturer,
                                manufacturingYear: asset.manufacturingYear,
                                sapId: asset.sapId,
                                serialNumber: asset.serialNumber,
                                assetThingname: asset.name,
                                locationCaption: location.caption,
                                groupCaption: group.groupCaption
                            });
                        }
                    }

                  }
            } else {
              logger.info(loggerBeginning + "There are not assets for the group " + group.groupCaption);
            }
          }
        } else {
          logger.info(loggerBeginning + "There are no assetGroups at the location " + location.caption);
        }
      }
    } else {
      logger.warn(loggerBeginning + "There are no locations.");
    }
    result.Sort({name:"databaseId", ascending:true});


// result: INFOTABLE dataShape: "HPMC.Asset.Saw.Info.DS"
    var result = me.QueryAssetByCompanyLocation({
    	locId: locId /* STRING */ ,
    	ucId: ucId /* STRING */
    });

    for (let i = 0; i < result.length; i++) {
    	if (result[i].machineType !== '' && result[i].machineType !== null) {
    		me.UpdateAssetImage({
    			assetThingname: result[i].name /* THINGNAME */
    		});
    	}
    }


