                                manufacturer: asset.manufacturer,
                                manufacturingYear: asset.manufacturingYear,
                                sapId: asset.sapId,
                                serialNumber: asset.serialNumber,
                                assetThingname: asset.name,
                                locationCaption: location.caption,
                                groupCaption: group.groupCaption
                            });
                        }
                    }

                  }
            } else {
              logger.info(loggerBeginning + "There are not assets for the group " + group.groupCaption);
            }
          }
        } else {
          logger.info(loggerBeginning + "There are no assetGroups at the location " + location.caption);
        }
      }
    } else {
      logger.warn(loggerBeginning + "There are no locations.");
    }
    result.Sort({name:"databaseId", ascending:true});


/*
 * @name UpdateAssetGroup
 * @date 20.08.2020
 * @author Georg Reckendorfer
 * @param locationThingname 		name of the location where the assetGroups should be updated
 * @param (not needed) editedAssetGroupTable 	table of the assetGroups which should be updated
 * @param id new value
 * @param caption new value
 * @param description new value
 * @param toBeEditedRow row with new values
 * Updates the assetGroups at the given location.
 *
 * [Marc Aurel Büttner] [01/03/2022]
 * Update assetGroup without Edit Grid --> use fields instead
 *
 * [Georg RECKENDORFER] [30.08.2022]
 * Update also property machineGroup in assets
 */
let loggerBeginning = "[HPMC.Asset.Helper:UpdateAssetGroup] ";
//logger.info(loggerBeginning + "Update assetGroup at Location " + locationThingname);
const ADMIN_CORE_MANAGER_ENTITY = Things["HPMC.Core.Administration.Manager"];

try {
    //get existing groups
    let location = Things[locationThingname];
    let allGroups = location.assetGroups;

    let row = allGroups.Find({
        groupId: toBeEditedRow.groupId,
        groupCaption: toBeEditedRow.groupCaption,
        groupDescription: toBeEditedRow.groupDescription
    });

    row.groupId = id;
    row.groupCaption = caption;
    row.groupDescription = description;

    let assets = row.assets;
    if (assets != undefined) {
        for (let i = 0; i < assets.length; i++) {
            let assetThingname = assets[i].assetThingname;
            Things[assetThingname].machineGroup = caption;
        }
    }

    Things[locationThingname].assetGroups = allGroups;

    // need to update machinetimer shiftplans if caption changes
    let manager_name = ADMIN_CORE_MANAGER_ENTITY.GetModuleManagerEntity({moduleName: "MachineTimer"});
    if (manager_name != undefined) {
        //logger.info(me.name + "Manager Name for Machinetimer = " + manager_name);
        let machinetimerManager = Things[manager_name];
        machinetimerManager.UpdateMachineGroupFromShiftplan({ucId: location.ucId, locId: location.locId, oldAssetGroupName: toBeEditedRow.groupCaption, newAssetGroupName: caption});
    }


    //result = "Asset Group " + id + " updated successfully.";
} catch (err) {
    logger.error("Error at " + me.name + ".UpdateAssetGroup [" + err.lineNumber + "]:" + err.message);
    result = "Update Asset Group " + id + " failed.";
}

