    * @date 11.12.2020
    * @author Isro Syaeful Iman
    * @param editedLocationTable "HPMC.Core.Asset.DS"
    * Takes an infotable as input and updates all Assets based on the information from the input-infoTable.
    */

    logger.info("[" + me.name + ":UpdateLocations]: Update all locations which are includeed in the input-infotable.");

    var editedLocationThingname;

    try{
        for(let i = 0; i < editedLocationTable.getRowCount(); i++){
            editedLocationThingname = editedLocationTable[i].name;

            Things[editedLocationThingname].address = editedLocationTable[i].address;
            Things[editedLocationThingname].caption = editedLocationTable[i].caption;
            Things[editedLocationThingname].location = editedLocationTable[i].location;
            Things[editedLocationThingname].locId = editedLocationTable[i].locId;
            Things[editedLocationThingname].ucId = editedLocationTable[i].ucId;
        }
    } catch(e){
     	logger.error(e);   
    }
